for type_ in union.types:
            graphql_type = self.from_type(type_)

            if isinstance(graphql_type, GraphQLInputObjectType):
                raise InvalidTypeInputForUnion(graphql_type)
            assert isinstance(graphql_type, (GraphQLObjectType, GraphQLUnionType))

            # If the graphql_type is a GraphQLUnionType, merge its child types
            if isinstance(graphql_type, GraphQLUnionType):
                # Add the child types of the GraphQLUnionType to the list of graphql_types,
                # filter out any duplicates
                for child_type in graphql_type.types:
                    if child_type not in graphql_types:
                        graphql_types.append(child_type)
            else:
                graphql_types.append(graphql_type)

for arg in update_args:
        if isinstance(arg, SetRevisionId):
            continue
        if isinstance(arg, list):
            continue

        if isinstance(arg, BaseUpdateOperator):
            raw = dict(arg.query)
        elif isinstance(arg, dict):
            raw = arg
        elif isinstance(arg, Mapping):
            raw = dict(arg)
        else:
            raise TypeError(
                f"Unsupported update expression type: {type(arg)!r}"
            )

        for operator_key, fields in raw.items():
            if not isinstance(fields, (dict, Mapping)):
                continue
            if operator_key not in consolidated:
                consolidated[operator_key] = {}
            consolidated[operator_key].update(fields)

if resolution.model_class is not None:
            fields = get_model_fields(resolution.model_class)
            if item in fields:
                field_info = fields[item]
                alias = field_info.alias if field_info.alias else item
                annotation = getattr(field_info, "annotation", None)
                child = ExpressionField._resolve_field(annotation)
                # Propagate is_link from parent when child is not
                # itself a new link boundary.
                if resolution.is_link and not child.is_link:
                    child = FieldResolution(
                        model_class=child.model_class, is_link=True
                    )
                return ExpressionField(
                    f"{self}.{alias}", field_resolution=child
                )

